changeSet.sql:
ALTER TABLE player_match_stats ADD COLUMN IF NOT EXISTS match_id BIGINT;
ALTER TABLE player_match_stats ADD COLUMN IF NOT EXISTS team VARCHAR(10);
ALTER TABLE player_match_stats ADD COLUMN IF NOT EXISTS damage INT;

DO $$ BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint WHERE conname = 'player_match_stats_fk01'
    ) THEN
        ALTER TABLE player_match_stats
            ADD CONSTRAINT player_match_stats_fk01
            FOREIGN KEY (match_id) REFERENCES match(match_id);
    END IF;
END $$;
